// Inputs from the 4 fetches
const customer = $('Loop per Customer').item.json;
const subData = $('Fetch MRR').item.json?.data || [];
const usageRaw = $('Fetch Usage (Mixpanel)').item.json;
const ticketsRaw = $('Fetch Tickets (Zendesk)').item.json;
const npsRaw = $('Fetch NPS (optional)').item.json;

// --- MRR ---
const mrr = subData.reduce((sum, s) => sum + (s.items?.data?.reduce((a, i) => a + (i.price?.unit_amount * (i.quantity || 1)), 0) || 0), 0) / 100;

// --- USAGE SCORE (0-100) ---
const usageBuckets = Array.isArray(usageRaw) ? usageRaw : (usageRaw?.data || []);
const activeDays = usageBuckets.filter(b => (b.value || b[1] || 0) > 0).length;
let usageScore;
if (activeDays >= 20) usageScore = 90;
else if (activeDays >= 12) usageScore = 70;
else if (activeDays >= 5) usageScore = 50;
else if (activeDays >= 1) usageScore = 30;
else usageScore = 10;

// --- SUPPORT SCORE ---
const tickets = Array.isArray(ticketsRaw) ? ticketsRaw : (ticketsRaw?.results || []);
const escalations = tickets.filter(t => t.priority === 'urgent' || t.priority === 'high' || t.tags?.includes('escalation')).length;
let supportScore;
if (tickets.length === 0) supportScore = 90;
else if (tickets.length <= 3 && escalations === 0) supportScore = 70;
else if (escalations === 0) supportScore = 50;
else if (escalations === 1) supportScore = 30;
else supportScore = 10;

// --- NPS SCORE ---
const npsResp = (npsRaw?.[0] || npsRaw?.responses?.[0]);
let npsScore = 60; // neutral default if no recent response
if (npsResp?.score !== undefined) {
  const s = npsResp.score;
  if (s >= 9) npsScore = 90;
  else if (s >= 7) npsScore = 70;
  else if (s >= 5) npsScore = 35;
  else npsScore = 10;
}

// --- RETENTION/MRR SCORE ---
const createdMs = (customer.created || 0) * 1000;
const tenureMonths = (Date.now() - createdMs) / (1000 * 60 * 60 * 24 * 30);
let retentionScore;
if (mrr === 0) retentionScore = 0;
else if (tenureMonths >= 12) retentionScore = 90;
else if (tenureMonths >= 6) retentionScore = 70;
else if (tenureMonths >= 3) retentionScore = 55;
else retentionScore = 40;

// --- WEIGHTED HEALTH SCORE ---
const weights = { usage: 0.30, support: 0.25, nps: 0.20, retention: 0.25 };
const healthScore = Math.round(
  usageScore * weights.usage +
  supportScore * weights.support +
  npsScore * weights.nps +
  retentionScore * weights.retention
);

let healthLevel;
if (healthScore >= 80) healthLevel = '🟢 Healthy';
else if (healthScore >= 60) healthLevel = '🟡 Watch';
else if (healthScore >= 40) healthLevel = '🟠 At Risk';
else healthLevel = '🔴 Critical';

return {
  json: {
    account_id: customer.id,
    account_name: customer.name || customer.email,
    mrr,
    usage_score: usageScore,
    support_score: supportScore,
    nps_score: npsScore,
    retention_score: retentionScore,
    health_score: healthScore,
    health_level: healthLevel,
    last_updated: new Date().toISOString(),
    score_delta_7d: 0 // populated by next node from sheet history
  }
};

const current = $('Calculate Health Score').item.json;
const previous = $('Lookup Previous Score').item.json;
const prevScore = previous?.health_score || current.health_score;
const delta = current.health_score - prevScore;

return {
  json: {
    ...current,
    score_delta_7d: delta
  }
};
